(()=>{"use strict";class t{constructor(){this.links=document.querySelectorAll(".tab-link"),this.panels=document.querySelectorAll(".tab-panel"),this.valid=Array.from(this.panels).map(t=>t.dataset.panel).filter(t=>Boolean(t)),this.fallback=this.valid[0]??"projects",this.init()}init(){this.links.forEach(t=>{t.addEventListener("click",()=>{const e=t.dataset.tab;e&&(window.location.hash===`#${e}`?this.activate(e):window.location.hash=e)})}),window.addEventListener("hashchange",()=>this.activate(this.currentTab())),this.activate(this.currentTab())}currentTab(){const t=window.location.hash.replace(/^#/,"");return this.valid.includes(t)?t:this.fallback}activate(t){this.links.forEach(e=>e.classList.toggle("active",e.dataset.tab===t)),this.panels.forEach(e=>e.classList.toggle("active",e.dataset.panel===t)),window.scrollTo({top:0,behavior:"smooth"})}}class e{constructor(){this.to="pbakare@alumni.cmu.edu";const t=document.getElementById("contact-form");t&&t.addEventListener("submit",e=>{e.preventDefault();const a=new FormData(t),i=String(a.get("name")??"").trim(),n=String(a.get("from")??"").trim(),s=String(a.get("message")??"").trim(),o=encodeURIComponent(`Portfolio message from ${i||"a visitor"}`),c=encodeURIComponent(`${s}\n\n— ${i}${n?` (${n})`:""}`);window.location.href=`mailto:${this.to}?subject=${o}&body=${c}`})}}document.addEventListener("DOMContentLoaded",()=>{new t,new e})})();